11	 *  WITH REGARD TO THIS SOFTWARE INCLUDING ALL IMPLIED WARRANTIES OF
12	 *  MERCHANTABILITY AND FITNESS. IN NO EVENT SHALL THE AUTHOR BE LIABLE FOR
13	 *  ANY SPECIAL, DIRECT, INDIRECT, OR CONSEQUENTIAL DAMAGES OR ANY DAMAGES
14	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 */
19	
20	#include "kernel/yosys.h"
21	#include "kernel/log_help.h"
22	
23	#ifdef YOSYS_ENABLE_PLUGINS
24	#  include <dlfcn.h>
25	#  include <filesystem>
26	namespace fs = std::filesystem;
27	#endif
28	
29	#ifdef YOSYS_ENABLE_PYTHON
30	#  include <Python.h>
31	#  include <pybind11/pybind11.h>
32	namespace py = pybind11;
33	#endif
34	
35	YOSYS_NAMESPACE_BEGIN
36	
37	std::map<std::string, void*> loaded_plugins;
38	#ifdef YOSYS_ENABLE_PYTHON
39	std::map<std::string, void*> loaded_python_plugins;
40	#endif
41	std::map<std::string, std::string> loaded_plugin_aliases;
42	
43	#ifdef YOSYS_ENABLE_PLUGINS
44	
45	static constexpr const char *path_delimiters = fs::path::preferred_separator == '\\' ? ";" : ":" ;
46	
47	inline const std::vector<fs::path> get_plugin_search_paths() {
48		std::vector<fs::path> result;
49		const char *yosys_plugin_path = std::getenv("YOSYS_PLUGIN_PATH");
50		if (yosys_plugin_path != nullptr && strlen(yosys_plugin_path)) {
51			// make mutable. std::string also manages allocation as a bonus
52			// guaranteed contiguous in c++>=11
53			std::string copy{yosys_plugin_path};
54			char *token = nullptr;
55			char *rest = &copy[0];
56			while ((token = strtok_r(rest, path_delimiters, &rest))) {
57				result.push_back(fs::path(token));
58			}
59		}
60		result.push_back(fs::path(proc_share_dirname()) / "plugins"); // lowest priority
61		return result;
62	}
63	
64	void load_plugin(std::string filename, std::vector<std::string> aliases)
65	{
66		std::string orig_filename = filename;
67		rewrite_filename(filename);
68	
69		// Would something like this better be put in `rewrite_filename`?
70		if (filename.find("/") == std::string::npos)
71			filename = "./" + filename;
72	
73	
74		#ifdef YOSYS_ENABLE_PYTHON
75		const bool is_loaded = loaded_plugins.count(orig_filename) && loaded_python_plugins.count(orig_filename);
76		#else
77		const bool is_loaded = loaded_plugins.count(orig_filename);
78		#endif
79	
80		fs::path full_path = fs::absolute(filename);
81	
82		if (!is_loaded) {
83			// Check if we're loading a python script
84			if (full_path.extension() == ".py") {
85				#ifdef YOSYS_ENABLE_PYTHON
86					fs::path plugin_python_path = full_path.parent_path();
87					fs::path basename = full_path.stem();
88	
89					py::object sys = py::module_::import("sys");
90					sys.attr("path").attr("insert")(0, py::str(plugin_python_path.c_str()));
91	
92					try {
93						auto module_container = py::module_::import(basename.c_str());
94						loaded_python_plugins[orig_filename] = module_container.ptr();
95					} catch (py::error_already_set &e) {
96						log_cmd_error("Can't load python module `%s': %s\n", basename, e.what());
97						return;
98					}
99					Pass::init_register();
100				#else
101					log_error(
102						"\n  This version of Yosys cannot load python plugins.\n"
103						"  Ensure Yosys is built with Python support to do so.\n"
104					);
105				#endif
106			} else {
107				// Otherwise we assume it's a native plugin
108				void *hdl = dlopen(filename.c_str(), RTLD_LAZY|RTLD_LOCAL);
109	
110				// We were unable to open the file, try to do so from plugin search
111				// paths
112				if (hdl == nullptr && orig_filename.find('/') == std::string::npos) {
113					const std::vector<fs::path> search_paths = get_plugin_search_paths();
114					for (const auto &search_path: search_paths) {
115						fs::path potential_path = search_path / orig_filename;
116						if (potential_path.extension() != ".so") {
117							potential_path = search_path / (orig_filename + ".so");
118						}
119						hdl = dlopen(potential_path.string().c_str(), RTLD_LAZY | RTLD_LOCAL);
120						if (hdl != nullptr) {
121							break;
122						}
123					}
124				}
125	
126				if (hdl == nullptr)
127					log_cmd_error("Can't load module `%s': %s\n", filename, dlerror());
128	
129				loaded_plugins[orig_filename] = hdl;
130				Pass::init_register();
131			}
132		}
133	
134		for (auto &alias : aliases)
135			loaded_plugin_aliases[alias] = orig_filename;
136	}
137	#else
138	void load_plugin(std::string, std::vector<std::string>)
139	{
140		log_error(
141			"\n  This version of Yosys cannot load plugins at runtime.\n"
142			"  Some plugins may have been included at build time.\n"
143			"  Use `yosys -H' to see the available built-in and plugin commands.\n"
144		);
145	}
146	#endif
147	
148	struct PluginPass : public Pass {
149		PluginPass() : Pass("plugin", "load and list loaded plugins") { }
150		bool formatted_help() override {
151			auto *help = PrettyHelp::get_current();
152			help->set_group("passes/status");
153			return false;
154		}
155		void help() override
156		{
157			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
158			log("\n");
159			log("    plugin [options]\n");
160			log("\n");
161			log("Load and list loaded plugins.\n");
162			log("\n");
163			log("    -i <plugin_filename>\n");
164			log("        Load (install) the specified plugin.\n");
165			log("\n");
166			log("    -a <alias_name>\n");
167			log("        Register the specified alias name for the loaded plugin\n");
168			log("\n");
169			log("    -l\n");
170			log("        List loaded plugins\n");
171			log("\n");
172		}
173		void execute(std::vector<std::string> args, RTLIL::Design *design) override
174		{
175			std::string plugin_filename;
176			std::vector<std::string> plugin_aliases;
177			bool list_mode = false;
178	
179			size_t argidx;
180			for (argidx = 1; argidx < args.size(); argidx++)
181			{
182				if ((args[argidx] == "-i") && argidx+1 < args.size() && plugin_filename.empty()) {
183					plugin_filename = args[++argidx];
184					continue;
185				}
186				if ((args[argidx] == "-a") && argidx+1 < args.size()) {
187					plugin_aliases.push_back(args[++argidx]);
188					continue;
189				}
190				if (args[argidx] == "-l") {
191					list_mode = true;
192					continue;
193				}
194				break;
195			}
196			extra_args(args, argidx, design, false);
197	
198			if (!plugin_filename.empty())
199				load_plugin(plugin_filename, plugin_aliases);
200	
201			if (list_mode)
202			{
203				log("\n");
204	#ifdef YOSYS_ENABLE_PYTHON
205				if (loaded_plugins.empty() and loaded_python_plugins.empty())
206	#else
207				if (loaded_plugins.empty())
208	#endif
209					log("No plugins loaded.\n");
210				else
211					log("Loaded plugins:\n");
212	
213				for (auto &it : loaded_plugins)
