210	void Pass::call(RTLIL::Design *design, std::string command)
211	{
212		std::vector<std::string> args;
213	
214		std::string cmd_buf = command;
215		std::string tok = next_token(cmd_buf, " \t\r\n", true);
216	
217		if (tok.empty())
218			return;
219	
220		if (tok[0] == '!') {
221	#if defined(YOSYS_ENABLE_SPAWN)
222			cmd_buf = command.substr(command.find('!') + 1);
223			while (!cmd_buf.empty() && (cmd_buf.back() == ' ' || cmd_buf.back() == '\t' ||
224					cmd_buf.back() == '\r' || cmd_buf.back() == '\n'))
225				cmd_buf.resize(cmd_buf.size()-1);
226			log_header(design, "Shell command: %s\n", cmd_buf);
227			int retCode = run_command(cmd_buf);
228			if (retCode != 0)
229				log_cmd_error("Shell command returned error code %d.\n", retCode);
230			return;
231	#else
232			log_cmd_error("Shell is not available.\n");
233	#endif
234		}
235	
236		while (!tok.empty()) {
237			if (tok[0] == '#') {
238				int stop;
239				for (stop = 0; stop < GetSize(cmd_buf); stop++)
240					if (cmd_buf[stop] == '\r' || cmd_buf[stop] == '\n')
241						break;
242				cmd_buf = cmd_buf.substr(stop);
243			} else
244			if (tok.back() == ';') {
245				int num_semikolon = 0;
246				while (!tok.empty() && tok.back() == ';')
247					tok.resize(tok.size()-1), num_semikolon++;
248				if (!tok.empty())
249					args.push_back(tok);
250				call(design, args);
251				args.clear();
252				if (num_semikolon == 2)
253					call(design, "clean");
254				if (num_semikolon == 3)
255					call(design, "clean -purge");
256			} else
257				args.push_back(tok);
258			bool found_nl = false;
259			for (auto c : cmd_buf) {
260				if (c == ' ' || c == '\t')
261					continue;
262				if (c == '\r' || c == '\n')
263					found_nl = true;
264				break;
265			}
266			if (found_nl) {
267				call(design, args);
268				args.clear();
269			}
270			tok = next_token(cmd_buf, " \t\r\n", true);
271		}
272	
273		call(design, args);
274	}
275	
276	void Pass::call(RTLIL::Design *design, std::vector<std::string> args)
277	{
278		if (args.size() == 0 || args[0][0] == '#' || args[0][0] == ':')
279			return;
280	
281		if (echo_mode) {
282			log("%s", create_prompt(design, 0));
283			for (size_t i = 0; i < args.size(); i++)
284				log("%s%s", i ? " " : "", args[i]);
285			log("\n");
286		}
287	
288		if (pass_register.count(args[0]) == 0)
289			log_cmd_error("No such command: %s (type 'help' for a command overview)\n", args[0]);
290		Pass *pass = pass_register[args[0]];
291	
292		// Collect garbage before the next pass if requested. No need to collect garbage after the last pass.
293		try_collect_garbage();
294		GarbageCollectionGuard gc_guard(pass->allow_garbage_collection_during_pass());
295	
296		if (pass->experimental_flag)
297			log_experimental(args[0]);
298	
299		size_t orig_sel_stack_pos = design->selection_stack.size();
300		auto state = pass->pre_execute();
301		pass->execute(args, design);
302		pass->post_execute(state);
303		while (design->selection_stack.size() > orig_sel_stack_pos)
304			design->pop_selection();
305	}
