460	FILE *Frontend::current_script_file = NULL;
461	std::string Frontend::last_here_document;
462	
463	void Frontend::extra_args(std::istream *&f, std::string &filename, std::vector<std::string> args, size_t argidx, bool bin_input)
464	{
465		bool called_with_fp = f != NULL;
466	
467		next_args.clear();
468	
469		if (argidx < args.size())
470		{
471			std::string arg = args[argidx];
472	
473			if (arg.compare(0, 1, "-") == 0)
474				cmd_error(args, argidx, "Unknown option or option in arguments.");
475			if (f != NULL)
476				cmd_error(args, argidx, "Extra filename argument in direct file mode.");
477	
478			filename = arg;
479			//Accommodate heredocs with EOT marker spaced out from "<<", e.g. "<< EOT" vs. "<<EOT"
480			if (filename == "<<" && argidx+1 < args.size())
481				filename += args[++argidx];
482			if (filename.compare(0, 2, "<<") == 0) {
483				if (filename.size() <= 2)
484					log_error("Missing EOT marker in here document!\n");
485				std::string eot_marker = filename.substr(2);
486				if (Frontend::current_script_file == nullptr)
487					filename = "<stdin>";
488				last_here_document.clear();
489				while (1) {
490					std::string buffer;
491					char block[4096];
492					while (1) {
493						if (fgets(block, 4096, Frontend::current_script_file == nullptr? stdin : Frontend::current_script_file) == nullptr)
494							log_error("Unexpected end of file in here document '%s'!\n", filename);
495						buffer += block;
496						if (buffer.size() > 0 && (buffer[buffer.size() - 1] == '\n' || buffer[buffer.size() - 1] == '\r'))
497							break;
498					}
499					size_t indent = buffer.find_first_not_of(" \t\r\n");
500					if (indent != std::string::npos && buffer.compare(indent, eot_marker.size(), eot_marker) == 0)
501						break;
502					last_here_document += buffer;
503				}
504				f = new std::istringstream(last_here_document);
505			} else {
506				rewrite_filename(filename);
507				vector<string> filenames = glob_filename(filename);
508				filename = filenames.front();
509				if (GetSize(filenames) > 1) {
510					next_args.insert(next_args.end(), args.begin(), args.begin()+argidx);
511					next_args.insert(next_args.end(), filenames.begin()+1, filenames.end());
512				}
513				yosys_input_files.insert(filename);
514				f = uncompressed(filename, bin_input ? std::ifstream::binary : std::ifstream::in);
515			}
516	
517			for (size_t i = argidx+1; i < args.size(); i++)
518				if (args[i].compare(0, 1, "-") == 0)
519					cmd_error(args, i, "Found option, expected arguments.");
520	
521			if (argidx+1 < args.size()) {
522				if (next_args.empty())
523					next_args.insert(next_args.end(), args.begin(), args.begin()+argidx);
524				next_args.insert(next_args.end(), args.begin()+argidx+1, args.end());
525				args.erase(args.begin()+argidx+1, args.end());
526			}
527		}
528	
529		if (f == NULL)
530			cmd_error(args, argidx, "No filename given.");
531	
532		if (called_with_fp)
533			args.push_back(filename);
534		args[0] = pass_name;
535		// cmd_log_args(args);
536	}
