541		char *s = strdup(command.c_str());
542		for (char *p = strtok(s, " \t\r\n"); p; p = strtok(NULL, " \t\r\n"))
543			args.push_back(p);
544		free(s);
545		frontend_call(design, f, filename, args);
546	}
