548	void Frontend::frontend_call(RTLIL::Design *design, std::istream *f, std::string filename, std::vector<std::string> args)
549	{
550		if (args.size() == 0)
551			return;
552		if (frontend_register.count(args[0]) == 0)
553			log_cmd_error("No such frontend: %s\n", args[0]);
554	
555		if (f != NULL) {
556			auto state = frontend_register[args[0]]->pre_execute();
557			frontend_register[args[0]]->execute(f, filename, args, design);
558			frontend_register[args[0]]->post_execute(state);
559		} else if (filename == "-") {
560			std::istream *f_cin = &std::cin;
561			auto state = frontend_register[args[0]]->pre_execute();
562			frontend_register[args[0]]->execute(f_cin, "<stdin>", args, design);
563			frontend_register[args[0]]->post_execute(state);
564		} else {
565			if (!filename.empty())
566				args.push_back(filename);
567			frontend_register[args[0]]->execute(args, design);
568		}
569	}
