668	void Backend::backend_call(RTLIL::Design *design, std::ostream *f, std::string filename, std::vector<std::string> args)
669	{
670		if (args.size() == 0)
671			return;
672		if (backend_register.count(args[0]) == 0)
673			log_cmd_error("No such backend: %s\n", args[0]);
674	
675		size_t orig_sel_stack_pos = design->selection_stack.size();
676	
677		if (f != NULL) {
678			auto state = backend_register[args[0]]->pre_execute();
679			backend_register[args[0]]->execute(f, filename, args, design);
680			backend_register[args[0]]->post_execute(state);
681		} else if (filename == "-") {
682			std::ostream *f_cout = &std::cout;
683			auto state = backend_register[args[0]]->pre_execute();
684			backend_register[args[0]]->execute(f_cout, "<stdout>", args, design);
685			backend_register[args[0]]->post_execute(state);
686		} else {
687			if (!filename.empty())
688				args.push_back(filename);
689			backend_register[args[0]]->execute(args, design);
690		}
691	
692		while (design->selection_stack.size() > orig_sel_stack_pos)
693			design->pop_selection();
694	}
